import{_ as a,o as t,c as o,a2 as i}from"./chunks/framework.C69UpXSI.js";const m=JSON.parse('{"title":"Comandi","description":"","frontmatter":{},"headers":[],"relativePath":"it/utilizzo/comandi.md","filePath":"it/utilizzo/comandi.md"}'),d={name:"it/utilizzo/comandi.md"};function s(n,e,c,l,r,p){return t(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="comandi" tabindex="-1">Comandi <a class="header-anchor" href="#comandi" aria-label="Permalink to &quot;Comandi&quot;">​</a></h1><p>I comandi slash di TurboDev.</p><p>Tutti i comandi iniziano con <code>/</code>. Digita <code>/</code> nella barra di input per aprire la palette dei comandi — naviga con <code>↑</code>/<code>↓</code> e seleziona con <code>Invio</code>.</p><h2 id="comandi-generali" tabindex="-1">Comandi generali <a class="header-anchor" href="#comandi-generali" aria-label="Permalink to &quot;Comandi generali&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Comando</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>/agent</code></td><td>Apre il selettore degli agenti</td></tr><tr><td><code>/clear</code></td><td>Cancella la cronologia della chat</td></tr><tr><td><code>/compact</code></td><td>Compatta la conversazione per liberare spazio nel contesto</td></tr><tr><td><code>/exit</code></td><td>Esci da TurboDev</td></tr><tr><td><code>/help</code></td><td>Mostra i comandi disponibili</td></tr><tr><td><code>/init</code></td><td>Crea o aggiorna <code>AGENTS.md</code></td></tr><tr><td><code>/model</code></td><td>Apre il selettore dei modelli</td></tr><tr><td><code>/new</code></td><td>Inizia una nuova sessione</td></tr><tr><td><code>/sessions</code></td><td>Elenca e passa da una sessione all&#39;altra</td></tr><tr><td><code>/setup</code></td><td>Esegue di nuovo la procedura guidata</td></tr><tr><td><code>/skills</code></td><td>Elenca le agent skill scoperte</td></tr><tr><td><code>/mcp</code></td><td>Elenca i server MCP e i tool</td></tr><tr><td><code>/mcp reload</code></td><td>Rilegge <code>.turbodev/mcp.json</code> e riconnette</td></tr><tr><td><code>/memory</code></td><td>Mostra le entry di memoria persistente</td></tr><tr><td><code>/memory add [cat] &lt;text&gt;</code></td><td>Aggiunge una entry (categorie: preferences, decisions, architecture, facts)</td></tr><tr><td><code>/memory clear [cat]</code></td><td>Cancella tutta la memoria o una categoria</td></tr><tr><td><code>/memory reload</code></td><td>Ricarica la memoria da disco</td></tr><tr><td><code>/economy</code></td><td>Mostra lo stato di economy mode</td></tr><tr><td><code>/economy eco</code></td><td>Attiva output conciso (diretto, no filler)</td></tr><tr><td><code>/economy ultra</code></td><td>Attiva output ultra-conciso (telegrafico)</td></tr><tr><td><code>/economy off</code></td><td>Disattiva economy mode</td></tr></tbody></table><h2 id="comandi-git" tabindex="-1">Comandi Git <a class="header-anchor" href="#comandi-git" aria-label="Permalink to &quot;Comandi Git&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Comando</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>/branch</code></td><td>Elenca i branch locali</td></tr><tr><td><code>/branch &lt;name&gt;</code></td><td>Passa al branch specificato</td></tr><tr><td><code>/commit &lt;msg&gt;</code></td><td>Aggiunge tutto allo staging e fa commit con il messaggio</td></tr><tr><td><code>/git add</code></td><td>Aggiunge file allo staging (tutti per impostazione predefinita)</td></tr><tr><td><code>/git diff</code></td><td>Mostra le modifiche non in staging</td></tr><tr><td><code>/git log</code></td><td>Mostra il log dei commit (10 per impostazione predefinita)</td></tr><tr><td><code>/git remote</code></td><td>Elenca i remote</td></tr><tr><td><code>/git stash</code></td><td>Salva le modifiche in stash</td></tr><tr><td><code>/git status</code></td><td>Mostra lo stato dell&#39;albero di lavoro</td></tr><tr><td><code>/pull</code></td><td>Effettua pull dal remote</td></tr><tr><td><code>/push</code></td><td>Effettua push del branch corrente sul remote</td></tr><tr><td><code>/rollback</code></td><td>Mostra i commit recenti per il rollback</td></tr></tbody></table><h2 id="comandi-github" tabindex="-1">Comandi GitHub <a class="header-anchor" href="#comandi-github" aria-label="Permalink to &quot;Comandi GitHub&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Comando</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>/gh auth</code></td><td>Avvia la procedura guidata di autenticazione GitHub</td></tr><tr><td><code>/pr &lt;titolo&gt;</code></td><td>Crea una pull request con il titolo specificato</td></tr><tr><td><code>/pr list</code></td><td>Elenca le pull request aperte</td></tr></tbody></table><h2 id="dettagli-dei-comandi" tabindex="-1">Dettagli dei comandi <a class="header-anchor" href="#dettagli-dei-comandi" aria-label="Permalink to &quot;Dettagli dei comandi&quot;">​</a></h2><h3 id="init" tabindex="-1">/init <a class="header-anchor" href="#init" aria-label="Permalink to &quot;/init&quot;">​</a></h3><p>Crea o aggiorna <code>AGENTS.md</code> nel tuo progetto.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/init</span></span></code></pre></div><p>Se <code>AGENTS.md</code> esiste già, puoi scegliere di:</p><ol><li><strong>Sovrascrivere</strong> — Ricominciare da capo</li><li><strong>Aggiungere</strong> — Inserire nuove sezioni al file esistente</li></ol><p>La procedura guidata rileva il tipo di progetto e genera le sezioni pertinenti.</p><h3 id="model" tabindex="-1">/model <a class="header-anchor" href="#model" aria-label="Permalink to &quot;/model&quot;">​</a></h3><p>Apre un selettore interattivo dei modelli.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/model</span></span></code></pre></div><p>Naviga con <code>↑</code>/<code>↓</code> o <code>j</code>/<code>k</code>, seleziona con un numero (1–9), annulla con <code>Esc</code> o <code>q</code>. Se ci sono più di 9 modelli, sono disponibili più pagine.</p><h3 id="agent" tabindex="-1">/agent <a class="header-anchor" href="#agent" aria-label="Permalink to &quot;/agent&quot;">​</a></h3><p>Apre il selettore degli agenti.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/agent</span></span></code></pre></div><p>Digita il numero dell&#39;agente per selezionarlo, premi <code>Esc</code> per annullare. Mostra tutti gli agenti primari disponibili con le relative descrizioni.</p><h3 id="setup" tabindex="-1">/setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;/setup&quot;">​</a></h3><p>Esegue di nuovo la procedura guidata iniziale per cambiare la chiave API o il modello.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/setup</span></span></code></pre></div><h3 id="clear" tabindex="-1">/clear <a class="header-anchor" href="#clear" aria-label="Permalink to &quot;/clear&quot;">​</a></h3><p>Cancella l&#39;intera cronologia della chat e il contesto della conversazione.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/clear</span></span></code></pre></div><h3 id="compact" tabindex="-1">/compact <a class="header-anchor" href="#compact" aria-label="Permalink to &quot;/compact&quot;">​</a></h3><p>Compatta la conversazione riassumendola tramite AI. Libera spazio nella finestra di contesto, permettendo sessioni più lunghe senza perdere i punti chiave della conversazione.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/compact</span></span></code></pre></div><p>L&#39;auto-compattazione si attiva al <strong>85%</strong> della finestra di contesto. Riceverai una notifica al <strong>75%</strong>. Usa <code>/compact</code> manualmente in qualsiasi momento.</p><h3 id="new" tabindex="-1">/new <a class="header-anchor" href="#new" aria-label="Permalink to &quot;/new&quot;">​</a></h3><p>Inizia una nuova sessione vuota. La sessione corrente viene salvata automaticamente e può essere ripresa in seguito con <code>/sessions</code>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/new</span></span></code></pre></div><h3 id="sessions" tabindex="-1">/sessions <a class="header-anchor" href="#sessions" aria-label="Permalink to &quot;/sessions&quot;">​</a></h3><p>Elenca tutte le sessioni salvate, ordinate per le più recenti. Seleziona una sessione digitandone il numero per ripristinarla.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/sessions</span></span></code></pre></div><p>Mostra ogni sessione con titolo, tempo relativo e numero di messaggi. Premi <code>Esc</code> per annullare.</p><h3 id="commit" tabindex="-1">/commit <a class="header-anchor" href="#commit" aria-label="Permalink to &quot;/commit&quot;">​</a></h3><p>Aggiunge tutte le modifiche allo staging e fa commit con il messaggio fornito.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/commit fix: risolto problema di login</span></span></code></pre></div><p>Equivalente a <code>git add -A &amp;&amp; git commit -m &quot;fix: risolto problema di login&quot;</code>.</p><h3 id="gh-auth" tabindex="-1">/gh auth <a class="header-anchor" href="#gh-auth" aria-label="Permalink to &quot;/gh auth&quot;">​</a></h3><p>Avvia la procedura guidata di autenticazione GitHub. Supporta il login via browser o token di accesso personale. Richiede che la <a href="https://cli.github/" target="_blank" rel="noreferrer">GitHub CLI (<code>gh</code>)</a> sia installata.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gh auth</span></span></code></pre></div><h3 id="skills" tabindex="-1">/skills <a class="header-anchor" href="#skills" aria-label="Permalink to &quot;/skills&quot;">​</a></h3><p>Elenca tutte le agent skill scoperte con stato, fonte e descrizione.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/skills</span></span></code></pre></div><p>Mostra il nome di ogni skill, se è abilitata o disabilitata, dove è stata trovata (builtin, globale o progetto) e la sua descrizione. Le skill vengono caricate da tre fonti in ordine di priorità: progetto (<code>.agents/skills/</code>) &gt; globale (<code>~/.config/turbodev/skills/</code>) &gt; builtin.</p><h3 id="mcp" tabindex="-1">/mcp <a class="header-anchor" href="#mcp" aria-label="Permalink to &quot;/mcp&quot;">​</a></h3><p>Elenca tutti i server MCP (Model Context Protocol) configurati con stato della connessione, numero di tool ed eventuali errori.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/mcp</span></span></code></pre></div><p>Formato dell&#39;output:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MCP Servers (1 connected, 5 tools total):</span></span>
<span class="line"><span>  ✓ filesystem            5 tools    connected</span></span>
<span class="line"><span>  ✗ db                    error       ECONNREFUSED</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Use /mcp reload to re-read .turbodev/mcp.json and reconnect.</span></span></code></pre></div><p>Icone di stato: <code>✓</code> connesso, <code>✗</code> errore, <code>○</code> altro. La barra di stato mostra <code>MCP:N</code> (magenta) quando ci sono N server connessi.</p><h3 id="mcp-reload" tabindex="-1">/mcp reload <a class="header-anchor" href="#mcp-reload" aria-label="Permalink to &quot;/mcp reload&quot;">​</a></h3><p>Rilegge <code>.turbodev/mcp.json</code>, disconnette i server rimossi/cambiati e connette quelli nuovi. I server invariati restano connessi (no churn).</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/mcp reload</span></span></code></pre></div><p>Usalo dopo aver modificato il file di configurazione. Vedi <a href="/turbodev/it/configurazione/mcp.html">configurazione MCP</a> per il riferimento completo.</p><h3 id="memory" tabindex="-1">/memory <a class="header-anchor" href="#memory" aria-label="Permalink to &quot;/memory&quot;">​</a></h3><p>Mostra tutte le entry di memoria persistente raggruppate per categoria. L&#39;AI usa questi fatti come contesto tra le sessioni.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/memory</span></span></code></pre></div><p>La memoria è salvata in <code>.turbodev/memory.md</code> (Markdown plain, gitignored). L&#39;AI può salvare fatti autonomamente tramite il tool <code>save_memory</code>, oppure puoi gestirli con i comandi seguenti. Vedi <a href="/turbodev/it/configurazione/memory.html">Memoria Persistente</a> per il riferimento completo.</p><h3 id="memory-add" tabindex="-1">/memory add <a class="header-anchor" href="#memory-add" aria-label="Permalink to &quot;/memory add&quot;">​</a></h3><p>Aggiunge una nuova entry di memoria. La categoria predefinita è <code>facts</code>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/memory add Use pnpm, never npm</span></span>
<span class="line"><span>/memory add preferences I prefer 2-space indentation</span></span>
<span class="line"><span>/memory add decisions We deploy to Vercel</span></span></code></pre></div><p>Categorie: <code>preferences</code>, <code>decisions</code>, <code>architecture</code>, <code>facts</code>.</p><h3 id="memory-clear" tabindex="-1">/memory clear <a class="header-anchor" href="#memory-clear" aria-label="Permalink to &quot;/memory clear&quot;">​</a></h3><p>Cancella tutta la memoria, o solo una categoria. Chiede conferma <code>[y/n]</code>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/memory clear              # cancella tutto</span></span>
<span class="line"><span>/memory clear decisions    # cancella una categoria</span></span></code></pre></div><h3 id="memory-reload" tabindex="-1">/memory reload <a class="header-anchor" href="#memory-reload" aria-label="Permalink to &quot;/memory reload&quot;">​</a></h3><p>Rilegge <code>.turbodev/memory.md</code> da disco. Usalo dopo aver modificato manualmente il file.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/memory reload</span></span></code></pre></div><h3 id="exit" tabindex="-1">/exit <a class="header-anchor" href="#exit" aria-label="Permalink to &quot;/exit&quot;">​</a></h3><p>Esce da TurboDev.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/exit</span></span></code></pre></div>`,79)])])}const u=a(d,[["render",s]]);export{m as __pageData,u as default};
